            //
            aIngress = (RotL64(aWorkLaneA[((aIndex + 1174U)) & S_BLOCK1], 22U) ^ RotL64(aWorkLaneB[((aIndex + 4330U)) & S_BLOCK1], 53U));
            aIngress ^= (RotL64(aFireLaneD[((aIndex + 16U)) & S_BLOCK1], 43U) ^ RotL64(aWaterLaneA[((S_BLOCK1 - aIndex + 3650U)) & S_BLOCK1], 5U));
