            //
            aOrbiterF = (aOrbiterF + aOrbiterG) + 0x716D33ACB863D905ULL;
            aOrbiterI = (aOrbiterI ^ aOrbiterF) ^ 0x11A84458BA12D625ULL;
            aOrbiterI = RotL64((aOrbiterI * 0x71F3B8F87B25F94FULL), 51U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterJ) + 0x96875EF8D1D5444DULL;
            aOrbiterA = (aOrbiterA ^ aOrbiterB) ^ 0xA3E1E69F3EEB2D7EULL;
