            //
            aWandererB = aWandererB + ((RotL64(aScatter, 40U) + RotL64(aOrbiterG, 21U)) + aOrbiterB);
            aWandererC = aWandererC ^ ((RotL64(aIngress, 5U) + aOrbiterH) + RotL64(aOrbiterK, 53U));
